INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('PSYCHOLOGY_SALES: Le principe de coherence (Cialdini): une personne qui dit oui a une petite demande dira plus facilement oui a une grande.', 'Coherence Cialdini: petit oui → grand oui', 'commercial', 'insight', 0.85, 'massive_boost_32', 'system'),
('PSYCHOLOGY_SALES: Le principe d autorite: les experts percus (titre, diplome, publication) convertissent 35% mieux.', 'Autorite expertise = +35% conversion', 'commercial', 'insight', 0.82, 'massive_boost_32', 'system'),
('PSYCHOLOGY_SALES: Le principe de rarete: les offres limitees dans le temps ou en quantite augmentent la demande de 40%.', 'Rarete temps/quantite = +40% demande', 'commercial', 'insight', 0.85, 'massive_boost_32', 'system'),
('PSYCHOLOGY_SALES: Le principe d affection: les gens achetent a ceux qu ils aiment. L humanisation de la marque est cle.', 'Affection: gens achetent a ceux qu ils aiment', 'commercial', 'insight', 0.82, 'massive_boost_32', 'system'),
('PSYCHOLOGY_SALES: Le principe de consensus: montrer que les pairs font la meme chose rassure et augmente la conversion de 20%.', 'Consensus: pairs font pareil = +20% conversion', 'commercial', 'insight', 0.82, 'massive_boost_32', 'system'),
('PSYCHOLOGY_SALES: Le framing effect: presenter 95% de satisfaction au lieu de 5% d insatisfaction change la perception de 40%.', 'Framing: 95% satisfaction > 5% insatisfaction = +40% perception', 'commercial', 'insight', 0.82, 'massive_boost_32', 'system'),
('PSYCHOLOGY_SALES: Le decoy effect: ajouter une 3e option (decoy) oriente 60% des choix vers l option ciblee.', 'Decoy effect: 3e option = 60% choix vers cible', 'commercial', 'insight', 0.82, 'massive_boost_32', 'system'),
('PSYCHOLOGY_SALES: Le sunk cost fallacy: les gens investissent plus dans ce qu ils ont deja commence. Le free trial exploite ce biais.', 'Sunk cost: trial = investissement debut = upgrade', 'commercial', 'insight', 0.80, 'massive_boost_32', 'system'),
('PSYCHOLOGY_SALES: Le peak-end rule: les gens jugent une experience par son pic et sa fin. Finir fort est cle.', 'Peak-end rule: finir fort = bonne perception', 'commercial', 'insight', 0.82, 'massive_boost_32', 'system'),
('PSYCHOLOGY_SALES: Le loss aversion: perdre 100€ fait 2x plus mal que gagner 100€ fait plaisir. Utiliser dans le copy.', 'Loss aversion: perte 2x plus forte que gain', 'commercial', 'insight', 0.85, 'massive_boost_32', 'system'),
('DATA_ANALYTICS: Le funnel analysis (ou les visiteurs abandonnent) est la premiere analyse a faire pour optimiser la conversion.', 'Funnel analysis = premiere analyse CRO', 'ceo', 'best_practice', 0.88, 'massive_boost_32', 'system'),
('DATA_ANALYTICS: Le RFM analysis (Recency, Frequency, Monetary) segmente les clients par valeur. Focus sur les VIP.', 'RFM: Recency + Frequency + Monetary = segmenter par valeur', 'ceo', 'best_practice', 0.82, 'massive_boost_32', 'system'),
('DATA_ANALYTICS: Le churn prediction model (IA qui predit le churn) permet d agir 30 jours avant le depart du client.', 'Churn prediction IA = agir 30j avant depart', 'retention', 'insight', 0.82, 'massive_boost_32', 'system'),
('DATA_ANALYTICS: Le LTV prediction (valeur vie client predite) guide le budget d acquisition acceptable par client.', 'LTV prediction = budget acquisition par client', 'ceo', 'insight', 0.82, 'massive_boost_32', 'system'),
('DATA_ANALYTICS: Les dashboards doivent etre consultables en < 3 clics. Au-dela personne ne les regarde.', 'Dashboard < 3 clics. Au-dela personne ne regarde', 'ceo', 'best_practice', 0.82, 'massive_boost_32', 'system'),
('COMPETITIVE_INTELLIGENCE: Alertes Google (nom concurrent) notifient en temps reel quand un concurrent est mentionne en ligne.', 'Alertes Google concurrent = veille temps reel', 'ceo', 'best_practice', 0.82, 'massive_boost_32', 'system'),
('COMPETITIVE_INTELLIGENCE: Les changelogs des concurrents revelent leur strategie produit. Les surveiller mensuellement.', 'Changelogs concurrents = strategie produit. Surveiller mensuel', 'ceo', 'best_practice', 0.80, 'massive_boost_32', 'system'),
('COMPETITIVE_INTELLIGENCE: Les offres d emploi des concurrents revelent leurs investissements futurs (data scientist = IA, SDR = outbound).', 'Offres emploi concurrents = investissements futurs', 'ceo', 'insight', 0.78, 'massive_boost_32', 'system'),
('COMPETITIVE_INTELLIGENCE: Le mystery shopping (se faire passer pour un prospect) revele le process de vente du concurrent.', 'Mystery shopping concurrent = comprendre process vente', 'ceo', 'best_practice', 0.78, 'massive_boost_32', 'system'),
('COMPETITIVE_INTELLIGENCE: L analyse des avis negatifs des concurrents sur G2/Capterra revele les opportunites de differenciation.', 'Avis negatifs concurrents G2 = opportunites differenciation', 'ceo', 'best_practice', 0.82, 'massive_boost_32', 'system'),
('SCALE_OPS: La documentation est le prerequis #1 pour scaler. Ce qui n est pas documente ne peut pas etre delegue.', 'Documentation = prerequis #1 scale. Non documente = non delegable', 'ceo', 'best_practice', 0.88, 'massive_boost_32', 'system'),
('SCALE_OPS: Les playbooks (guides pas a pas) pour chaque process business permettent de recruter et former en 1 semaine.', 'Playbooks = recruter et former en 1 semaine', 'ceo', 'best_practice', 0.85, 'massive_boost_32', 'system'),
('SCALE_OPS: Les KPIs de chaque equipe doivent etre affiches (dashboard partage) pour l alignement et la transparence.', 'KPIs dashboard partage = alignement + transparence', 'ceo', 'best_practice', 0.82, 'massive_boost_32', 'system'),
('SCALE_OPS: L automatisation doit etre priorisee par ROI: automatiser les taches repetitives a fort volume en premier.', 'Automatiser: repetitif + fort volume en premier = max ROI', 'ceo', 'best_practice', 0.85, 'massive_boost_32', 'system'),
('SCALE_OPS: Le bottleneck (goulot d etranglement) dans le process doit etre identifie et resolu avant de scaler.', 'Identifier bottleneck avant scaler. Resoudre d abord', 'ceo', 'best_practice', 0.85, 'massive_boost_32', 'system'),
('PAYMENTS: Le failed payment recovery (dunning) automatise recupere 30-50% des paiements echoues.', 'Dunning automatise = 30-50% paiements echoues recuperes', 'comptable', 'insight', 0.85, 'massive_boost_32', 'system'),
('PAYMENTS: Le smart retry (reessayer le paiement a un moment optimal) augmente la recuperation de 15%.', 'Smart retry paiement = +15% recuperation', 'comptable', 'insight', 0.80, 'massive_boost_32', 'system'),
('PAYMENTS: L email de pre-dunning (votre carte expire bientot, mettez-la a jour) previent 20% des echecs de paiement.', 'Email pre-dunning carte expire = prevenir 20% echecs', 'comptable', 'best_practice', 0.82, 'massive_boost_32', 'system'),
('PAYMENTS: Le multiple payment methods (CB + PayPal + virement + BNPL) augmente la conversion de 30%.', 'Multiple payment methods = +30% conversion', NULL, 'insight', 0.85, 'massive_boost_32', 'system'),
('PAYMENTS: Le Stripe Invoicing automatise la facturation et les rappels de paiement. Reduit les retards de 40%.', 'Stripe Invoicing = -40% retards paiement', 'comptable', 'insight', 0.82, 'massive_boost_32', 'system'),
('GROWTH_LOOPS: Le paid growth loop: acquerir → monetiser → reinvestir. Le ratio reinvestissement doit etre > 50% du profit.', 'Paid growth loop: acquerir → monetiser → reinvestir > 50%', 'ceo', 'best_practice', 0.82, 'massive_boost_32', 'system'),
('GROWTH_LOOPS: Le viral growth loop: user → invite → new user → invite. Le K-factor doit etre > 1 pour la croissance exponentielle.', 'Viral loop: K-factor > 1 = croissance exponentielle', 'ceo', 'insight', 0.85, 'massive_boost_32', 'system'),
('GROWTH_LOOPS: Le content growth loop: creer contenu → SEO trafic → conversion → client cree contenu (avis, UGC).', 'Content loop: creer → SEO → conversion → UGC', 'ceo', 'insight', 0.82, 'massive_boost_32', 'system'),
('GROWTH_LOOPS: Le data growth loop: plus d utilisateurs → plus de data → meilleur produit → plus d utilisateurs.', 'Data loop: users → data → meilleur produit → users', 'ceo', 'insight', 0.85, 'massive_boost_32', 'system'),
('GROWTH_LOOPS: Le sales-led growth loop: close deal → case study → attract prospect → close deal.', 'Sales loop: close → case study → prospect → close', 'commercial', 'insight', 0.80, 'massive_boost_32', 'system'),
('PRICING_PSYCHOLOGY: Le prix en 9 (49€, 99€, 199€) est le plus utilise et augmente les ventes de 8% vs les prix ronds.', 'Prix en 9 = +8% ventes vs prix ronds', 'commercial', 'insight', 0.82, 'massive_boost_32', 'system'),
('PRICING_PSYCHOLOGY: Le prix barré (~~149€~~ 99€) augmente la valeur percue de 40%. Toujours montrer l economie.', 'Prix barre = +40% valeur percue', 'commercial', 'insight', 0.85, 'massive_boost_32', 'system'),
('PRICING_PSYCHOLOGY: Le pack (bundle) a un prix inferieur a la somme des elements = sentiment de bonne affaire.', 'Bundle prix < somme elements = bonne affaire', 'commercial', 'insight', 0.85, 'massive_boost_32', 'system'),
('PRICING_PSYCHOLOGY: Le prix par jour (3€/jour au lieu de 90€/mois) rend le cout negligeable et augmente la conversion.', 'Prix/jour vs /mois = cout negligeable +conversion', 'commercial', 'insight', 0.82, 'massive_boost_32', 'system'),
('PRICING_PSYCHOLOGY: Le plan du milieu est choisi par 60% des clients. Positionner l offre cible au milieu.', 'Plan milieu choisi 60%. Positionner offre cible au milieu', 'commercial', 'insight', 0.85, 'massive_boost_32', 'system'),
('CUSTOMER_EXPERIENCE: La premiere impression se forme en 7 secondes. Le site/app doit communiquer la valeur en < 7s.', 'Premiere impression 7s. Valeur en < 7s', 'commercial', 'insight', 0.85, 'massive_boost_32', 'system'),
('CUSTOMER_EXPERIENCE: Le wow moment (moment ou le client dit wow) doit etre engineer dans le parcours utilisateur.', 'Wow moment = engineer dans parcours utilisateur', 'onboarding', 'best_practice', 0.85, 'massive_boost_32', 'system'),
('CUSTOMER_EXPERIENCE: Le proactive support (anticiper les problemes avant qu ils arrivent) augmente la satisfaction de 30%.', 'Support proactif = +30% satisfaction', 'retention', 'best_practice', 0.82, 'massive_boost_32', 'system'),
('CUSTOMER_EXPERIENCE: Le self-service (FAQ, guides, videos) est prefere par 67% des clients vs l appel telephonique.', 'Self-service prefere 67% vs telephone', NULL, 'insight', 0.85, 'massive_boost_32', 'system'),
('CUSTOMER_EXPERIENCE: Le closing the loop (informer le client quand son feedback a ete implemente) augmente la loyalty de 25%.', 'Close the loop feedback → loyalty +25%', 'retention', 'best_practice', 0.82, 'massive_boost_32', 'system'),
('TECHNICAL_SEO: Le Core Web Vitals: LCP (Largest Contentful Paint) < 2.5s, INP (Interaction to Next Paint) < 200ms, CLS < 0.1.', 'Core Web Vitals: LCP < 2.5s, INP < 200ms, CLS < 0.1', 'seo', 'best_practice', 0.90, 'massive_boost_32', 'system'),
('TECHNICAL_SEO: Le HTTPS est un facteur de ranking confirme. Les sites HTTP sont marques non securises par Chrome.', 'HTTPS = facteur ranking. HTTP = non securise Chrome', 'seo', 'best_practice', 0.92, 'massive_boost_32', 'system'),
('TECHNICAL_SEO: Le mobile-first indexing: Google indexe la version mobile en premier. Si le mobile est mauvais, le ranking souffre.', 'Mobile-first indexing: mobile mauvais = ranking souffre', 'seo', 'insight', 0.90, 'massive_boost_32', 'system'),
('TECHNICAL_SEO: Les 404 errors (pages introuvables) doivent etre redirigees en 301 vers des pages pertinentes.', '404 → 301 vers pages pertinentes', 'seo', 'best_practice', 0.88, 'massive_boost_32', 'system'),
('TECHNICAL_SEO: Le crawl budget: les grands sites (10K+ pages) doivent optimiser le robots.txt pour que Google crawle les pages importantes.', 'Crawl budget: optimiser robots.txt grands sites 10K+', 'seo', 'best_practice', 0.82, 'massive_boost_32', 'system'),
('STARTUP_LEGAL: Le pacte d associes est obligatoire pour proteger les fondateurs. Clauses cles: good/bad leaver, drag/tag along.', 'Pacte associes: good/bad leaver, drag/tag along', 'ceo', 'best_practice', 0.85, 'massive_boost_32', 'system'),
('STARTUP_LEGAL: Le vesting des parts (4 ans avec 1 an de cliff) protege contre le depart premature d un co-fondateur.', 'Vesting 4 ans + 1 an cliff = protection co-fondateur', 'ceo', 'best_practice', 0.85, 'massive_boost_32', 'system'),
('STARTUP_LEGAL: La propriete intellectuelle (code, design, marque) doit etre detenue par la societe, pas par les fondateurs.', 'PI = detenue par societe, pas fondateurs', 'ceo', 'best_practice', 0.88, 'massive_boost_32', 'system'),
('STARTUP_LEGAL: Les freelances/prestataires doivent signer une clause de cession de PI dans leur contrat.', 'Freelances: clause cession PI dans contrat', 'ceo', 'best_practice', 0.85, 'massive_boost_32', 'system'),
('STARTUP_LEGAL: Le NDA (accord de confidentialite) est standard avant de partager des infos sensibles avec des partenaires/investisseurs.', 'NDA standard avant partage infos sensibles', 'ceo', 'best_practice', 0.82, 'massive_boost_32', 'system'),
('CASHFLOW: Le delai de paiement moyen en France: 45 jours. Imposer des CGV a 30 jours pour ameliorer le cashflow.', 'Delai paiement FR: 45j moyen. CGV 30j pour cashflow', 'comptable', 'best_practice', 0.82, 'massive_boost_32', 'system'),
('CASHFLOW: L affacturage (ceder ses factures a un facteur) fournit le cash immediatement. Cout: 1-3% de la facture.', 'Affacturage = cash immediat. Cout 1-3%', 'comptable', 'insight', 0.78, 'massive_boost_32', 'system'),
('CASHFLOW: Le paiement annuel upfront (vs mensuel) ameliore le cashflow de 40% et reduit le churn de 50%.', 'Paiement annuel upfront = +40% cashflow -50% churn', 'comptable', 'insight', 0.85, 'massive_boost_32', 'system'),
('CASHFLOW: La tresorerie previsionnelle sur 12 mois (projection des entrees/sorties) evite 80% des surprises financieres.', 'Tresorerie previsionnelle 12 mois = -80% surprises', 'comptable', 'best_practice', 0.85, 'massive_boost_32', 'system'),
('CASHFLOW: Le runway (nombre de mois avant la faillite) doit toujours etre > 6 mois. < 3 mois = urgence absolue.', 'Runway > 6 mois. < 3 = urgence absolue', 'comptable', 'best_practice', 0.90, 'massive_boost_32', 'system'),
('INNOVATION_2026: L IA agentique (equipes d agents IA coordonnes) redefinit la productivite des PME. KeiroAI est pionnier.', 'IA agentique PME = revolution. KeiroAI pionnier', 'ceo', 'insight', 0.90, 'massive_boost_32', 'system'),
('INNOVATION_2026: Le voice commerce (achat par commande vocale) represente 5% des achats en ligne et croit de 20%/an.', 'Voice commerce: 5% achats online, +20%/an', NULL, 'insight', 0.75, 'massive_boost_32', 'system'),
('INNOVATION_2026: Les digital twins (replique numerique d un business) permettent de simuler des scenarios avant de les executer.', 'Digital twins business = simuler scenarios avant execution', 'ceo', 'insight', 0.75, 'massive_boost_32', 'system'),
('INNOVATION_2026: Le spatial computing (Apple Vision Pro, Meta Quest) ouvre de nouvelles experiences d achat immersives.', 'Spatial computing = experiences achat immersives', NULL, 'insight', 0.72, 'massive_boost_32', 'system'),
('INNOVATION_2026: Les modeles IA open-source (Llama, Mistral) democratisent l IA pour les startups a budget limite.', 'IA open-source Llama/Mistral = democratisation startups', 'ceo', 'insight', 0.85, 'massive_boost_32', 'system')
INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('NICHE_MARKETING: Les marques de niche (specialisees) ont 3x plus de fidelite que les marques generalistes.', 'Niche marketing = 3x fidelite vs generaliste', 'marketing', 'insight', 0.82, 'massive_boost_33', 'system'),
('NICHE_MARKETING: Le positionnement ultra-niche (le meilleur outil X pour les Y) convertit 5x mieux que le positionement large.', 'Positionnement ultra-niche = 5x conversion', 'marketing', 'insight', 0.85, 'massive_boost_33', 'system'),
('NICHE_MARKETING: Les communautes de niche (Reddit subreddits, Discord servers) sont les meilleurs canaux pour tester un produit.', 'Communautes niche = meilleur canal test produit', 'marketing', 'best_practice', 0.82, 'massive_boost_33', 'system'),
('NICHE_MARKETING: Le contenu de niche a moins de competition SEO. Plus facile de ranker #1 sur un mot-cle niche.', 'Contenu niche = moins competition SEO = rank #1 plus facile', 'seo', 'insight', 0.85, 'massive_boost_33', 'system'),
('NICHE_MARKETING: Le pricing premium est accepte dans les niches car les alternatives sont rares et la valeur est claire.', 'Pricing premium niche = accepte car alternatives rares', 'commercial', 'insight', 0.82, 'massive_boost_33', 'system'),
('CROSS_SELL: Le cross-sell au bon moment (apres la satisfaction, pas avant) augmente le panier de 20% sans friction.', 'Cross-sell apres satisfaction = +20% panier sans friction', 'commercial', 'best_practice', 0.85, 'massive_boost_33', 'system'),
('CROSS_SELL: Les recommandations basees sur le comportement (les clients qui ont achete X achetent aussi Y) convertissent 3x mieux.', 'Recommandation comportementale = 3x conversion cross-sell', 'commercial', 'insight', 0.85, 'massive_boost_33', 'system'),
('CROSS_SELL: Le bundle apres achat (ajoutez Y pour seulement Z€ de plus) a un taux d acceptation de 15-25%.', 'Bundle post-achat = 15-25% acceptation', 'commercial', 'insight', 0.82, 'massive_boost_33', 'system'),
('CROSS_SELL: L email de cross-sell J+7 apres achat (basé sur l achat precedent) a un CTR de 8% et une conversion de 3%.', 'Email cross-sell J+7 = 8% CTR, 3% conversion', 'email', 'insight', 0.80, 'massive_boost_33', 'system'),
('UPSELL_TACTICS: Le feature gating (montrer les features premium grisees) cree le desir d upgrade naturellement.', 'Feature gating = desir upgrade naturel', 'retention', 'best_practice', 0.85, 'massive_boost_33', 'system'),
('UPSELL_TACTICS: Le usage-based upsell (vous avez utilise 90% de votre quota) est le trigger le plus efficace.', 'Usage 90% quota = trigger upsell le plus efficace', 'retention', 'best_practice', 0.88, 'massive_boost_33', 'system'),
('UPSELL_TACTICS: Le ROI calculator (montrer la valeur supplementaire du plan superieur) augmente les upgrades de 30%.', 'ROI calculator upsell = +30% upgrades', 'retention', 'insight', 0.82, 'massive_boost_33', 'system'),
('UPSELL_TACTICS: Le free trial du plan superieur (7 jours de Pro gratuit) convertit 25% des users qui l essaient.', 'Trial plan superieur 7j = 25% conversion', 'retention', 'insight', 0.82, 'massive_boost_33', 'system'),
('UPSELL_TACTICS: Le comparison table (montrer ce que le plan actuel n a pas vs le plan superieur) est le meilleur outil visuel.', 'Comparison table plans = meilleur outil visuel upsell', 'retention', 'best_practice', 0.82, 'massive_boost_33', 'system'),
('MARKET_TIMING: Le timing de lancement compte pour 42% du succes d une startup (Bill Gross, Idealab).', 'Timing = 42% succes startup (Bill Gross)', 'ceo', 'insight', 0.82, 'massive_boost_33', 'system'),
('MARKET_TIMING: Le first-mover advantage est surestime. Le fast follower (copier + ameliorer) reussit souvent mieux.', 'First-mover surestimé. Fast follower = copier + ameliorer', 'ceo', 'insight', 0.82, 'massive_boost_33', 'system'),
('MARKET_TIMING: Les marches en croissance de 20%+/an pardonnent les erreurs. Les marches stagnants ne pardonnent rien.', 'Marche +20%/an pardonne erreurs. Stagnant = impitoyable', 'ceo', 'insight', 0.82, 'massive_boost_33', 'system'),
('MARKET_TIMING: Le blue ocean strategy (creer un nouveau marche) elimine la competition mais necessite plus d education.', 'Blue ocean: nouveau marche, 0 competition, plus education', 'ceo', 'insight', 0.80, 'massive_boost_33', 'system'),
('MARKET_TIMING: Le category creation (definir une nouvelle categorie de produit) est le moat le plus puissant si reussi.', 'Category creation = moat le plus puissant si reussi', 'ceo', 'insight', 0.80, 'massive_boost_33', 'system'),
('CONTENT_AI: Les outils IA de generation de contenu (Claude, GPT) reduisent le temps de creation de 70% mais la relecture humaine reste indispensable.', 'IA contenu = -70% temps. Relecture humaine indispensable', 'content', 'best_practice', 0.88, 'massive_boost_33', 'system'),
('CONTENT_AI: Le contenu IA doit etre enrichi de donnees personnelles (experience, anecdotes, opinions) pour se demarquer.', 'Contenu IA + donnees personnelles = differenciation', 'content', 'best_practice', 0.88, 'massive_boost_33', 'system'),
('CONTENT_AI: Les images IA (Midjourney, DALL-E, Flux) sont acceptables pour les illustrations mais pas pour les photos de produit.', 'Images IA: illustrations oui, photos produit non', 'content', 'best_practice', 0.82, 'massive_boost_33', 'system'),
('CONTENT_AI: Le fact-checking du contenu IA est obligatoire. Les hallucinations sont frequentes sur les chiffres et les dates.', 'Fact-check contenu IA obligatoire. Hallucinations frequentes', 'content', 'best_practice', 0.92, 'massive_boost_33', 'system'),
('CONTENT_AI: L IA est un assistant de creation, pas un remplacement. Le contenu sans touche humaine est detectable et penalise.', 'IA = assistant pas remplacement. Sans humain = detectable', 'content', 'best_practice', 0.88, 'massive_boost_33', 'system'),
('EMAIL_STRATEGY: La segmentation est le facteur #1 de performance email. Plus la segmentation est fine, meilleurs sont les resultats.', 'Segmentation email = facteur #1 performance', 'email', 'best_practice', 0.90, 'massive_boost_33', 'system'),
('EMAIL_STRATEGY: Les 4 types de segmentation: demographique, comportementale, psychographique, transactionnelle.', 'Segmentation: demo, comportement, psycho, transactionnel', 'email', 'best_practice', 0.85, 'massive_boost_33', 'system'),
('EMAIL_STRATEGY: Le triggered email (envoye automatiquement apres une action) a 8x plus d ouvertures que le broadcast.', 'Triggered email = 8x ouvertures vs broadcast', 'email', 'insight', 0.88, 'massive_boost_33', 'system'),
('EMAIL_STRATEGY: Le taux de clic moyen email: 2-5%. Au-dessus de 5% = excellent. En dessous de 1% = probleme de contenu/CTA.', 'Email CTR: 2-5% moyen, >5% excellent, <1% probleme', 'email', 'insight', 0.85, 'massive_boost_33', 'system'),
('EMAIL_STRATEGY: Le unsubscribe rate doit etre < 0.5% par campagne. Au-dessus = contenu non pertinent pour le segment.', 'Unsubscribe < 0.5%/campagne. Au-dessus = non pertinent', 'email', 'best_practice', 0.85, 'massive_boost_33', 'system'),
('SOCIAL_STRATEGY: Le content mix ideal par plateforme: IG (visuel + Reels), LinkedIn (texte + carrousel), TikTok (video courte), X (texte + thread).', 'Content mix: IG visuel/Reels, LI texte/carrousel, TT video, X texte/thread', 'content', 'best_practice', 0.85, 'massive_boost_33', 'system'),
('SOCIAL_STRATEGY: Le social media audit trimestriel (analyser ce qui fonctionne/pas) est obligatoire pour optimiser.', 'Social media audit trimestriel = optimisation obligatoire', 'content', 'best_practice', 0.82, 'massive_boost_33', 'system'),
('SOCIAL_STRATEGY: Le community management (repondre aux commentaires en < 1h) augmente l engagement de 40%.', 'Community management < 1h reponse = +40% engagement', 'content', 'best_practice', 0.85, 'massive_boost_33', 'system'),
('SOCIAL_STRATEGY: Les collaborations entre comptes (Instagram Collab, TikTok Duet) doublent la portee des deux cotes.', 'Collabs IG/TikTok = 2x portee des 2 cotes', 'content', 'insight', 0.85, 'massive_boost_33', 'system'),
('SOCIAL_STRATEGY: Le User Generated Content (UGC) est 4x plus credible que le contenu de marque. Encourager et repost.', 'UGC = 4x credibilite. Encourager + repost', 'content', 'insight', 0.85, 'massive_boost_33', 'system'),
('ADS_STRATEGY: Le creative testing framework: lancer 3-5 creatives par ad set, tuer celles avec CTR < 1% apres 1000 impressions.', 'Test creatives: 3-5/ad set. Tuer CTR < 1% apres 1000 impressions', 'ads', 'best_practice', 0.85, 'massive_boost_33', 'system'),
('ADS_STRATEGY: Le funnel ads: TOFU (awareness, video views) → MOFU (consideration, traffic) → BOFU (conversion, purchase).', 'Funnel ads: TOFU awareness → MOFU consideration → BOFU conversion', 'ads', 'best_practice', 0.88, 'massive_boost_33', 'system'),
('ADS_STRATEGY: Le budget test minimum par creative: 50€. En dessous, pas assez de data pour conclure.', 'Budget test min/creative: 50€. Sinon pas assez data', 'ads', 'best_practice', 0.82, 'massive_boost_33', 'system'),
('ADS_STRATEGY: Le kill rule: couper une campagne qui n atteint pas le CPA cible apres 3x le CPA cible de depense.', 'Kill rule: couper apres 3x CPA cible de depense', 'ads', 'best_practice', 0.82, 'massive_boost_33', 'system'),
('ADS_STRATEGY: Le scaling progressif (+20-30%/jour) est plus stable que le scaling brutal (doublement du budget).', 'Scaling +20-30%/jour > doublement brutal', 'ads', 'best_practice', 0.85, 'massive_boost_33', 'system'),
('COPY_TECHNIQUES: Le specifique bat le generique: "augmentez vos ventes de 37%" > "augmentez vos ventes".', 'Copy specifique > generique. 37% > augmenter', 'content', 'best_practice', 0.88, 'massive_boost_33', 'system'),
('COPY_TECHNIQUES: La voix active (nous livrons en 24h) bat la voix passive (la livraison est effectuee en 24h).', 'Voix active > passive en copy', 'content', 'best_practice', 0.85, 'massive_boost_33', 'system'),
('COPY_TECHNIQUES: Les phrases courtes (< 20 mots) sont lues par 90% des lecteurs. Les longues (40+ mots) par 40%.', 'Phrases < 20 mots = 90% lu. 40+ = 40% lu', 'content', 'insight', 0.82, 'massive_boost_33', 'system'),
('COPY_TECHNIQUES: Le pattern interrupt (phrase surprenante au milieu d un texte) relance l attention du lecteur.', 'Pattern interrupt mid-texte = relancer attention', 'content', 'best_practice', 0.80, 'massive_boost_33', 'system'),
('COPY_TECHNIQUES: Le risque reversal (si ca ne marche pas, on vous rembourse) elimine la derniere objection avant l achat.', 'Risque reversal = eliminer derniere objection', 'commercial', 'best_practice', 0.85, 'massive_boost_33', 'system'),
('TRUST_SIGNALS: Le SSL certificate (cadenas vert) est attendu par 84% des visiteurs pour faire confiance a un site.', 'SSL cadenas = 84% visiteurs attendent pour confiance', NULL, 'insight', 0.88, 'massive_boost_33', 'system'),
('TRUST_SIGNALS: Les badges de paiement securise (Visa, Mastercard, PayPal) augmentent la conversion checkout de 12%.', 'Badges paiement securise = +12% conversion checkout', NULL, 'insight', 0.82, 'massive_boost_33', 'system'),
('TRUST_SIGNALS: Les mentions presse (Vu dans Le Monde, Forbes, etc.) augmentent la credibilite de 35%.', 'Mentions presse = +35% credibilite', NULL, 'insight', 0.82, 'massive_boost_33', 'system'),
('TRUST_SIGNALS: Le compteur de clients (rejoint par 10 000+ entrepreneurs) est le social proof le plus impactant.', 'Compteur clients = social proof #1 impact', NULL, 'insight', 0.85, 'massive_boost_33', 'system'),
('TRUST_SIGNALS: La page A propos avec photo de l equipe augmente la confiance de 25%. Les gens achetent a des humains.', 'Page A propos + photos equipe = +25% confiance', NULL, 'insight', 0.82, 'massive_boost_33', 'system'),
('MOBILE_UX: Le thumb zone (zone accessible au pouce) doit contenir les boutons d action principaux sur mobile.', 'Thumb zone = boutons principaux sur mobile', NULL, 'best_practice', 0.85, 'massive_boost_33', 'system'),
('MOBILE_UX: Le hamburger menu cache 50% de la navigation. Preferer la bottom tab bar pour les actions frequentes.', 'Hamburger cache 50%. Bottom tab bar = meilleur', NULL, 'insight', 0.82, 'massive_boost_33', 'system'),
('MOBILE_UX: Le swipe gesture (balayer pour supprimer, liker) est plus naturel que les boutons sur mobile.', 'Swipe gesture > boutons sur mobile = plus naturel', NULL, 'insight', 0.80, 'massive_boost_33', 'system'),
('MOBILE_UX: Les formulaires sur mobile doivent utiliser le bon type de clavier (numerique pour telephone, email pour email).', 'Formulaires mobile: type clavier adapte (num, email)', NULL, 'best_practice', 0.85, 'massive_boost_33', 'system'),
('MOBILE_UX: Le infinite scroll fonctionne pour les feeds. La pagination pour les catalogues produit et les resultats de recherche.', 'Infinite scroll = feeds. Pagination = catalogues + recherche', NULL, 'best_practice', 0.82, 'massive_boost_33', 'system'),
('WELLNESS_DIGITAL: Le screen time moyen est de 7h/jour. Les apps qui proposent des pauses bien-etre augmentent la retention de 15%.', 'Screen time 7h/j. Pauses bien-etre = +15% retention', NULL, 'insight', 0.75, 'massive_boost_33', 'system'),
('DURABILITE_BUSINESS: Les entreprises B Corp ont une croissance 28% plus rapide que les entreprises traditionnelles.', 'B Corp = +28% croissance vs traditionnel', NULL, 'insight', 0.78, 'massive_boost_33', 'system'),
('DURABILITE_BUSINESS: Le green marketing (communiquer sur ses actions environnementales) augmente la preference de marque de 20%.', 'Green marketing = +20% preference marque', NULL, 'insight', 0.78, 'massive_boost_33', 'system'),
('VOICE_TECH: Les assistants vocaux (Alexa, Google) traitent 8 milliards de requetes par mois. Optimiser pour la recherche vocale.', 'Assistants vocaux 8 Mds requetes/mois. Optimiser', 'seo', 'insight', 0.78, 'massive_boost_33', 'system'),
('BLOCKCHAIN: Le Web3 loyalty (NFTs comme cartes de fidelite) offre une portabilite et une tracabilite uniques.', 'Web3 loyalty NFTs = portabilite + tracabilite', NULL, 'insight', 0.72, 'massive_boost_33', 'system'),
('QUANTUM: Le quantum computing impactera le marketing via l optimisation en temps reel de millions de variables simultanement.', 'Quantum computing: optimisation temps reel millions variables', NULL, 'insight', 0.68, 'massive_boost_33', 'system'),
('KEIROAI_VISION: KeiroAI est le premier assistant marketing IA avec une equipe de 17 agents specialises travaillant en synergie.', 'KeiroAI = premier assistant marketing IA 17 agents', 'ceo', 'best_practice', 0.95, 'massive_boost_33', 'system'),
('KEIROAI_VISION: La mission de KeiroAI: democratiser l acces a une equipe marketing d elite pour chaque entrepreneur.', 'KeiroAI mission: equipe marketing elite pour chaque entrepreneur', 'ceo', 'best_practice', 0.95, 'massive_boost_33', 'system'),
('KEIROAI_VISION: KeiroAI grandit en intelligence avec chaque client grace au RAG et aux apprentissages partages.', 'KeiroAI grandit avec chaque client via RAG', 'ceo', 'insight', 0.92, 'massive_boost_33', 'system'),
('KEIROAI_VISION: Le CEO agent de KeiroAI est le differenciation #1: un directeur marketing IA qui coordonne tous les agents.', 'CEO agent = differenciation #1 KeiroAI', 'ceo', 'best_practice', 0.95, 'massive_boost_33', 'system'),
('KEIROAI_VISION: KeiroAI vise 10 000 clients payants d ici fin 2027. Chaque client enrichit le systeme pour tous les autres.', 'KeiroAI objectif: 10K clients fin 2027', 'ceo', 'insight', 0.88, 'massive_boost_33', 'system')
INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('WEBDESIGN: Le above-the-fold (ce qui est visible sans scroller) doit contenir le headline, la proposition de valeur et le CTA.', 'Above fold: headline + value prop + CTA', NULL, 'best_practice', 0.88, 'massive_boost_34', 'system'),
('WEBDESIGN: Les pages longues (scrolling) convertissent 30% mieux que les pages courtes pour les offres complexes.', 'Pages longues = +30% conversion offres complexes', NULL, 'insight', 0.80, 'massive_boost_34', 'system'),
('WEBDESIGN: Le sticky header (menu fixe en haut) augmente la navigation de 15% et le temps sur site de 10%.', 'Sticky header = +15% navigation +10% temps site', NULL, 'insight', 0.80, 'massive_boost_34', 'system'),
('WEBDESIGN: Le chat widget en bas a droite est le placement standard. Le deplacer reduit l utilisation de 40%.', 'Chat widget bas-droite = standard. Deplacer = -40%', NULL, 'insight', 0.80, 'massive_boost_34', 'system'),
('WEBDESIGN: Le breadcrumb (fil d Ariane) ameliore la navigation et le SEO en montrant la hierarchie de la page.', 'Breadcrumb = navigation + SEO hierarchie', 'seo', 'best_practice', 0.82, 'massive_boost_34', 'system'),
('GROWTH_TIPS: Le Product Hunt launch genere 1000-10000 visiteurs en 1 jour. Planifier 2 semaines avant le launch day.', 'Product Hunt: 1K-10K visiteurs/jour. Planifier 2 sem avant', 'marketing', 'insight', 0.80, 'massive_boost_34', 'system'),
('GROWTH_TIPS: Le Hacker News (Show HN) attire un public tech qualifie. Un post en front page = 5000+ visiteurs.', 'Hacker News Show HN = 5K+ visiteurs tech', 'marketing', 'insight', 0.78, 'massive_boost_34', 'system'),
('GROWTH_TIPS: Le IndieHackers community est ideal pour les micro-SaaS. Partager les revenus en transparence = followers.', 'IndieHackers: transparence revenus = followers micro-SaaS', 'marketing', 'insight', 0.78, 'massive_boost_34', 'system'),
('GROWTH_TIPS: Le build in public (construire en public, partager les progres) attire les early adopters et les investisseurs.', 'Build in public = early adopters + investisseurs', 'marketing', 'best_practice', 0.82, 'massive_boost_34', 'system'),
('GROWTH_TIPS: Le AppSumo launch (lifetime deal) genere du cash et des users rapidement mais a faible marge.', 'AppSumo lifetime deal: cash + users rapide, faible marge', 'marketing', 'insight', 0.78, 'massive_boost_34', 'system'),
('COLD_OUTREACH: Le ice breaker personnalise (mention d un post recent, d un accomplissement) augmente le taux de reponse de 30%.', 'Ice breaker personnalise = +30% reponse cold outreach', 'commercial', 'best_practice', 0.85, 'massive_boost_34', 'system'),
('COLD_OUTREACH: Le CTA du cold email doit etre une question simple (est-ce que 15 min mardi vous irait?) pas un paragraphe.', 'CTA cold email: question simple 15 min. Pas paragraphe', 'email', 'best_practice', 0.85, 'massive_boost_34', 'system'),
('COLD_OUTREACH: Le PS dans un cold email est lu par 79% des lecteurs. Y mettre un social proof ou un chiffre cle.', 'PS cold email: 79% lu. Social proof ou chiffre cle', 'email', 'insight', 0.80, 'massive_boost_34', 'system'),
('COLD_OUTREACH: La personalization at scale (templates + variables dynamiques) permet d envoyer 100 emails personnalises/jour.', 'Personalization at scale: templates + variables = 100 emails perso/jour', 'email', 'best_practice', 0.82, 'massive_boost_34', 'system'),
('COLD_OUTREACH: Le reply rate ideal pour le cold email B2B: 5-10%. Au-dessus de 15% = sequence excellente.', 'Cold email B2B reply rate: 5-10% bon, >15% excellent', 'email', 'insight', 0.82, 'massive_boost_34', 'system'),
('CUSTOMER_FEEDBACK: Le CSAT (Customer Satisfaction Score) mesure la satisfaction post-interaction. Ideal: > 85%.', 'CSAT > 85% = bonne satisfaction', 'retention', 'best_practice', 0.82, 'massive_boost_34', 'system'),
('CUSTOMER_FEEDBACK: Le feedback qualitatif (interview 30 min) revele des insights que les metriques quantitatives ne montrent pas.', 'Interview qualitative 30 min = insights invisibles aux metriques', 'ceo', 'best_practice', 0.85, 'massive_boost_34', 'system'),
('CUSTOMER_FEEDBACK: Le feature voting (Canny, UserVoice) priorise le roadmap avec la voix du client.', 'Feature voting Canny = prioriser roadmap voix client', 'ceo', 'best_practice', 0.82, 'massive_boost_34', 'system'),
('CUSTOMER_FEEDBACK: Les churn surveys doivent etre envoyees immediatement apres la cancellation (pas 1 semaine plus tard).', 'Churn survey: immediatement apres cancel. Pas 1 semaine', 'retention', 'best_practice', 0.85, 'massive_boost_34', 'system'),
('CUSTOMER_FEEDBACK: Les reviews positives doivent etre repostees (temoignages) sur le site, les reseaux et dans les emails.', 'Reviews positives = repost sur site + social + emails', 'marketing', 'best_practice', 0.85, 'massive_boost_34', 'system'),
('SAAS_PRICING: Le grandfathering (garder l ancien prix pour les clients existants) augmente la fidelite de 30%.', 'Grandfathering ancien prix = +30% fidelite', 'ceo', 'best_practice', 0.82, 'massive_boost_34', 'system'),
('SAAS_PRICING: L augmentation de prix annuelle de 5-10% est standard et acceptee si elle s accompagne de nouvelles features.', 'Augmentation prix 5-10%/an standard si nouvelles features', 'ceo', 'best_practice', 0.82, 'massive_boost_34', 'system'),
('SAAS_PRICING: Les plans custom (Enterprise) doivent avoir un formulaire de contact, pas un prix affiche.', 'Enterprise: formulaire contact, pas prix affiche', 'commercial', 'best_practice', 0.85, 'massive_boost_34', 'system'),
('SAAS_PRICING: Le starter plan doit etre assez limite pour que les users serieux upgradent, mais assez genereux pour montrer la valeur.', 'Starter: limite pour upgrade + genereux pour valeur', 'ceo', 'best_practice', 0.85, 'massive_boost_34', 'system'),
('SAAS_PRICING: Les add-ons (fonctionnalites a la carte) augmentent l ARPU de 20-30% sans forcer l upgrade de plan.', 'Add-ons a la carte = +20-30% ARPU sans upgrade force', 'ceo', 'insight', 0.82, 'massive_boost_34', 'system'),
('INFRA_TIPS: Le monitoring des couts (alertes quand les depenses depassent un seuil) evite les factures surprises.', 'Monitoring couts + alertes seuil = eviter factures surprises', 'comptable', 'best_practice', 0.85, 'massive_boost_34', 'system'),
('INFRA_TIPS: Le auto-scaling (ajuster les ressources automatiquement selon la charge) optimise cout et performance.', 'Auto-scaling = optimiser cout + performance', 'ceo', 'best_practice', 0.82, 'massive_boost_34', 'system'),
('INFRA_TIPS: Le blue-green deployment (2 environnements identiques) permet un rollback instantane en cas de probleme.', 'Blue-green deployment = rollback instantane', 'ceo', 'best_practice', 0.82, 'massive_boost_34', 'system'),
('INFRA_TIPS: Le database connection pooling est obligatoire pour les apps serverless. Sans pooling = connexions epuisees.', 'DB connection pooling obligatoire serverless', 'ceo', 'best_practice', 0.88, 'massive_boost_34', 'system'),
('INFRA_TIPS: Les environment variables doivent etre stockees dans un vault securise (Vercel env, Supabase secrets). Jamais dans le code.', 'Env vars: vault securise. Jamais dans le code', 'ceo', 'best_practice', 0.92, 'massive_boost_34', 'system'),
