('AUTOMATION_ADVANCED: Les webhooks (evenements en temps reel entre services) sont la colle de l automatisation moderne.', 'Webhooks = colle automatisation moderne', 'ceo', 'insight', 0.85, 'massive_boost_34', 'system'),
('AUTOMATION_ADVANCED: Le no-code automation (Zapier, Make) permet aux non-techniciens d automatiser 80% de leurs workflows.', 'No-code auto Zapier/Make = 80% workflows pour non-tech', 'ceo', 'insight', 0.82, 'massive_boost_34', 'system'),
('NEGOTIATION_ADVANCED: Le concept de ZOPA (Zone of Possible Agreement) definit l espace de negociation viable pour les 2 parties.', 'ZOPA = zone accord viable negociation', 'commercial', 'insight', 0.80, 'massive_boost_34', 'system'),
('NEGOTIATION_ADVANCED: L integrative negotiation (win-win, creer de la valeur) > distributive (win-lose, diviser un gateau fixe).', 'Negotiation integrative win-win > distributive win-lose', 'commercial', 'best_practice', 0.82, 'massive_boost_34', 'system'),
('NEGOTIATION_ADVANCED: Toujours negocier la valeur totale (scope, timeline, extras) pas juste le prix.', 'Negocier valeur totale (scope, timeline, extras) pas juste prix', 'commercial', 'best_practice', 0.82, 'massive_boost_34', 'system'),
('NEGOTIATION_ADVANCED: Le bundling strategique (combiner produits/services) permet de justifier le prix total sans debat unitaire.', 'Bundling strategique = justifier prix total sans debat unitaire', 'commercial', 'best_practice', 0.80, 'massive_boost_34', 'system'),
('CULTURE_CLIENT: La culture orientee client (customer-centric) augmente la retention de 25% et le NPS de 20 points.', 'Culture customer-centric = +25% retention +20 NPS', 'ceo', 'insight', 0.82, 'massive_boost_34', 'system'),
('CULTURE_CLIENT: Chaque employe doit lire 5 tickets support par semaine pour rester connecte aux problemes clients.', 'Employes: 5 tickets support/semaine = connecte clients', 'ceo', 'best_practice', 0.78, 'massive_boost_34', 'system'),
('CULTURE_CLIENT: Le Voice of the Customer (VoC) program centralise les feedbacks de tous les canaux pour des insights actionables.', 'VoC program = centraliser feedbacks tous canaux', 'ceo', 'best_practice', 0.82, 'massive_boost_34', 'system'),
('CULTURE_CLIENT: Le customer journey mapping (visualiser toutes les interactions) identifie les moments de verite critiques.', 'Customer journey mapping = moments de verite critiques', 'marketing', 'best_practice', 0.85, 'massive_boost_34', 'system')
INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('MICRO_CONTENT: Les tweets < 80 caracteres ont 17% plus d engagement que les tweets longs sur X.', 'Tweet < 80 chars = +17% engagement X', 'content', 'insight', 0.80, 'massive_boost_35', 'system'),
