('SAAS_TRENDS: Les integrations natives (connecter avec les outils existants du client) sont le facteur #2 de choix SaaS apres le prix.', 'Integrations natives = facteur #2 choix SaaS apres prix', 'ceo', 'insight', 0.82, 'massive_boost_35', 'system'),
('MARKETING_TRENDS: Le intent data (signaux d intention d achat) permet de cibler les prospects au bon moment.', 'Intent data = cibler prospects au bon moment', 'commercial', 'insight', 0.80, 'massive_boost_35', 'system'),
('MARKETING_TRENDS: Le conversational marketing (chat en temps reel) remplace les formulaires pour la generation de leads.', 'Conversational marketing > formulaires pour leadgen', 'chatbot', 'insight', 0.82, 'massive_boost_35', 'system'),
('CONTENT_MONETIZATION: Les abonnements contenu premium (Substack, Patreon) generent des revenus recurrents previsibles.', 'Abonnement contenu premium = revenus recurrents previsibles', 'content', 'insight', 0.80, 'massive_boost_35', 'system'),
('CONTENT_MONETIZATION: Le contenu sponsorise doit etre clairement identifie (partenariat). L authenticite est non-negociable.', 'Contenu sponsorise: identifier clairement. Authenticite obligatoire', 'content', 'best_practice', 0.88, 'massive_boost_35', 'system'),
('CONTENT_MONETIZATION: Les cours en ligne bases sur du contenu existant (blog → cours) monetisent le savoir 10x.', 'Blog → cours en ligne = monetisation 10x', 'content', 'insight', 0.80, 'massive_boost_35', 'system'),
('PRODUCT_LED: Le free plan dans le PLG doit etre assez bon pour creer l habitude mais avec des limites strategiques.', 'PLG free plan: assez bon pour habitude + limites strategiques', 'ceo', 'best_practice', 0.85, 'massive_boost_35', 'system'),
('PRODUCT_LED: Le PQL (Product Qualified Lead) est un user qui a atteint un seuil d usage. Plus qualifie que le MQL.', 'PQL > MQL: base sur usage reel pas comportement marketing', 'ceo', 'insight', 0.82, 'massive_boost_35', 'system'),
('PRODUCT_LED: Le self-serve checkout (acheter sans parler a un vendeur) doit etre disponible pour les plans < 500€/mois.', 'Self-serve checkout pour plans < 500€/mois', 'ceo', 'best_practice', 0.82, 'massive_boost_35', 'system'),
('PRODUCT_LED: Le in-app upgrade prompt au moment du wall (limite atteinte) convertit 3x mieux que l email.', 'In-app upgrade au wall = 3x conversion vs email', 'retention', 'insight', 0.85, 'massive_boost_35', 'system'),
('PRODUCT_LED: Le reverse trial (commencer avec toutes les features puis downgrader) a un taux de conversion 2x superieur au freemium classique.', 'Reverse trial = 2x conversion vs freemium classique', 'ceo', 'insight', 0.82, 'massive_boost_35', 'system'),
('FINANCE_STARTUP: Le monthly financial review (revue financiere mensuelle) detecte les tendances 3 mois avant la crise.', 'Review financiere mensuelle = detecter tendances 3 mois avant crise', 'comptable', 'best_practice', 0.85, 'massive_boost_35', 'system'),
('FINANCE_STARTUP: Le budget glissant (revu chaque mois vs fixe pour l annee) est 40% plus precis.', 'Budget glissant mensuel = 40% plus precis', 'comptable', 'best_practice', 0.80, 'massive_boost_35', 'system'),
('FINANCE_STARTUP: Les metrics financieres a tracker: MRR, ARR, burn rate, runway, LTV, CAC, gross margin.', 'Metrics financieres: MRR, ARR, burn, runway, LTV, CAC, gross margin', 'comptable', 'best_practice', 0.88, 'massive_boost_35', 'system'),
('FINANCE_STARTUP: Le bridge financing (financement pont entre 2 levees) coute cher (12-20% interet) mais evite la faillite.', 'Bridge financing: 12-20% interet. Evite faillite', 'comptable', 'insight', 0.78, 'massive_boost_35', 'system'),
('FINANCE_STARTUP: Le revenue-based financing (RBF) est une alternative a la dilution: rembourser un % du CA futur.', 'RBF = alternative dilution. Rembourser % CA futur', 'comptable', 'insight', 0.78, 'massive_boost_35', 'system'),
('TEAM_BUILDING: Les equipes de 5-7 personnes sont les plus efficaces. Au-dela de 8, la communication se degrade.', 'Equipes 5-7 = plus efficaces. >8 = communication degrade', 'rh', 'insight', 0.82, 'massive_boost_35', 'system'),
('TEAM_BUILDING: Le premier hire d une startup doit etre le complement du fondateur (si tech → hire business, et vice versa).', 'Premier hire = complement fondateur (tech↔business)', 'rh', 'best_practice', 0.82, 'massive_boost_35', 'system'),
('TEAM_BUILDING: Les freelances sont ideaux pour les taches ponctuelles. Les employes pour les taches strategiques recurentes.', 'Freelances: ponctuel. Employes: strategique recurrent', 'rh', 'best_practice', 0.82, 'massive_boost_35', 'system'),
('TEAM_BUILDING: Le culture fit est aussi important que le skill fit. Un talent toxique coute plus qu il ne rapporte.', 'Culture fit = aussi important que skill fit. Toxique = cout net', 'rh', 'best_practice', 0.85, 'massive_boost_35', 'system'),
('TEAM_BUILDING: Les 1:1 hebdomadaires de 30 min entre manager et report sont l outil #1 de retention des talents.', '1:1 hebdo 30 min = outil #1 retention talents', 'rh', 'best_practice', 0.82, 'massive_boost_35', 'system'),
('REMOTE_WORK: Les rituels d equipe (daily standup, weekly all-hands) sont 2x plus importants en remote qu en presentiel.', 'Rituels equipe remote = 2x plus importants qu en presentiel', 'rh', 'best_practice', 0.82, 'massive_boost_35', 'system'),
('REMOTE_WORK: La documentation est le pilier du remote work. Tout ce qui n est pas ecrit n existe pas.', 'Remote work: documentation = pilier. Non ecrit = inexistant', 'rh', 'best_practice', 0.85, 'massive_boost_35', 'system'),
('REMOTE_WORK: Les outils de collaboration async (Notion, Loom, Slack) sont plus productifs que les meetings synchrones.', 'Async tools (Notion, Loom, Slack) > meetings synchrones', 'rh', 'insight', 0.82, 'massive_boost_35', 'system'),
('REMOTE_WORK: Le home office stipend (allocation pour amenager le bureau a domicile) augmente la productivite de 15%.', 'Home office stipend = +15% productivite', 'rh', 'insight', 0.78, 'massive_boost_35', 'system'),
('REMOTE_WORK: Les retreats d equipe (2-3 jours en personne tous les 3-6 mois) maintiennent la cohesion d equipe.', 'Retreats equipe 2-3j / 3-6 mois = cohesion', 'rh', 'best_practice', 0.80, 'massive_boost_35', 'system'),
('CRISIS_MANAGEMENT: Le plan de continuite d activite (PCA) doit couvrir: serveur down, piratage, perte de donnees, employe cle parti.', 'PCA: serveur down, piratage, perte data, employe cle parti', 'ceo', 'best_practice', 0.85, 'massive_boost_35', 'system'),
('CRISIS_MANAGEMENT: La communication de crise: rapide (< 30 min), transparente, empathique, avec un plan d action.', 'Comm crise: < 30 min, transparente, empathique, plan action', 'ceo', 'best_practice', 0.88, 'massive_boost_35', 'system'),
('CRISIS_MANAGEMENT: Le post-mortem sans blame (blameless post-mortem) apres chaque incident ameliore les processes de 40%.', 'Post-mortem sans blame = +40% amelioration processes', 'ceo', 'best_practice', 0.82, 'massive_boost_35', 'system'),
('CRISIS_MANAGEMENT: Le backup plan pour chaque fournisseur critique (si Brevo tombe, utiliser Resend) doit etre teste.', 'Backup plan fournisseur critique teste. Ex: Brevo down → Resend', 'ceo', 'best_practice', 0.85, 'massive_boost_35', 'system'),
('CRISIS_MANAGEMENT: Le status page (page de statut publique) reduit les tickets support de 60% pendant un incident.', 'Status page publique = -60% tickets pendant incident', 'ceo', 'insight', 0.82, 'massive_boost_35', 'system'),
('INDUSTRY_HEALTHCARE: La telemedecine doit respecter le RGPD + le secret medical. Les donnees sante sont les plus reglementees.', 'Telemedecine: RGPD + secret medical. Donnees sante ultra reglementees', NULL, 'best_practice', 0.88, 'massive_boost_35', 'system'),
('INDUSTRY_EDUCATION: Le marche EdTech francais: 2 milliards € en 2026. Les CPF et OPCO financent les formations certifiantes.', 'EdTech FR 2 Mds€ 2026. CPF + OPCO financent', NULL, 'insight', 0.78, 'massive_boost_35', 'system'),
('INDUSTRY_FINTECH: Le marche fintech FR: 5 milliards € en 2026. Les neo-banques et solutions de paiement dominent.', 'Fintech FR 5 Mds€ 2026. Neo-banques + paiement', NULL, 'insight', 0.78, 'massive_boost_35', 'system'),
('INDUSTRY_PROPTECH: Le marche proptech FR (immobilier tech): 1.5 milliard €. La gestion locative et les visites virtuelles dominent.', 'PropTech FR 1.5 Md€. Gestion locative + visites virtuelles', NULL, 'insight', 0.75, 'massive_boost_35', 'system'),
('INDUSTRY_AGRITECH: L agriculture connectee (IoT, IA, drones) reduit les couts de 20% et augmente les rendements de 15%.', 'AgriTech IoT/IA/drones = -20% couts +15% rendements', NULL, 'insight', 0.75, 'massive_boost_35', 'system'),
('INDUSTRY_LEGALTECH: Le marche legaltech FR: 500M€. La redaction automatisee de contrats et la gestion documentaire dominent.', 'LegalTech FR 500M€. Contrats auto + gestion docs', NULL, 'insight', 0.75, 'massive_boost_35', 'system'),
('INDUSTRY_HRTECH: Le marche HRTech FR: 1 milliard €. Le recrutement IA et le bien-etre au travail sont les segments en croissance.', 'HRTech FR 1 Md€. Recrutement IA + bien-etre', NULL, 'insight', 0.75, 'massive_boost_35', 'system'),
('FUNNEL_OPTIMIZATION: Le top of funnel doit generer 10x plus de leads que le nombre de clients necessaires.', 'TOFU: 10x leads vs clients necessaires', 'commercial', 'best_practice', 0.82, 'massive_boost_35', 'system'),
('FUNNEL_OPTIMIZATION: Le middle of funnel est souvent le maillon faible. Le nurturing par email + contenu est essentiel.', 'MOFU = maillon faible. Email nurturing + contenu = essentiel', 'commercial', 'best_practice', 0.82, 'massive_boost_35', 'system'),
('FUNNEL_OPTIMIZATION: Le bottom of funnel necessite des temoignages, case studies et une proposition de valeur claire.', 'BOFU: temoignages + case studies + value prop claire', 'commercial', 'best_practice', 0.85, 'massive_boost_35', 'system'),
('FUNNEL_OPTIMIZATION: Le flywheel (roue d inertie) remplace le funnel lineaire: attract → engage → delight → repeat.', 'Flywheel > funnel lineaire: attract → engage → delight → repeat', 'marketing', 'insight', 0.82, 'massive_boost_35', 'system'),
('FUNNEL_OPTIMIZATION: Le dark funnel (parcours invisible: podcasts ecoutes, DM prives, conversations offline) represente 70% de l influence.', 'Dark funnel = 70% influence. Invisible aux analytics', 'marketing', 'insight', 0.80, 'massive_boost_35', 'system'),
('WEBSITE_OPTIMIZATION: Le hero section doit repondre a 3 questions en 5s: quoi (produit), pour qui (persona), pourquoi (benefice).', 'Hero section: quoi + pour qui + pourquoi en 5s', NULL, 'best_practice', 0.88, 'massive_boost_35', 'system'),
('WEBSITE_OPTIMIZATION: La page 404 personnalisee (avec navigation + recherche) recupere 30% des visiteurs perdus.', 'Page 404 personnalisee = 30% visiteurs recuperes', 'seo', 'best_practice', 0.80, 'massive_boost_35', 'system'),
('WEBSITE_OPTIMIZATION: Le footer doit contenir: liens importants, social media, newsletter signup, trust badges, legal.', 'Footer: liens + social + newsletter + trust + legal', NULL, 'best_practice', 0.82, 'massive_boost_35', 'system'),
('WEBSITE_OPTIMIZATION: La barre de recherche est utilisee par 30% des visiteurs. Les sites avec recherche convertissent 2x mieux.', 'Barre recherche: 30% utilisent. Sites avec recherche = 2x conversion', NULL, 'insight', 0.82, 'massive_boost_35', 'system'),
('WEBSITE_OPTIMIZATION: Le exit popup avec offre specifique (pas generique) recupere 5-10% des visiteurs qui partent.', 'Exit popup offre specifique = 5-10% recuperation sortie', NULL, 'insight', 0.80, 'massive_boost_35', 'system'),
('PERSONAL_FINANCE: Les entrepreneurs doivent se payer un salaire fixe, meme petit. Mixer perso/pro est une erreur legale et fiscale.', 'Entrepreneur: salaire fixe obligatoire. Pas mixer perso/pro', 'comptable', 'best_practice', 0.85, 'massive_boost_35', 'system'),
('PERSONAL_FINANCE: L epargne de precaution (6 mois de depenses personnelles) protege le fondateur en cas d echec.', 'Epargne precaution 6 mois depenses = protection fondateur', 'comptable', 'best_practice', 0.82, 'massive_boost_35', 'system'),
('PERSONAL_FINANCE: Le PEA (Plan d Epargne en Actions) est le meilleur vehicule fiscal pour investir en France (0% impot apres 5 ans).', 'PEA = 0% impot apres 5 ans. Meilleur vehicule fiscal FR', 'comptable', 'insight', 0.80, 'massive_boost_35', 'system'),
('PERSONAL_FINANCE: La diversification (ne pas mettre tous ses oeufs dans le meme panier) protege contre les aleas.', 'Diversification = protection contre aleas', 'comptable', 'best_practice', 0.82, 'massive_boost_35', 'system'),
('KEIROAI_BEST_PRACTICES: Les agents KeiroAI doivent toujours prioriser la qualite sur la quantite. 1 post excellent > 5 posts mediocres.', 'KeiroAI: qualite > quantite. 1 excellent > 5 mediocres', NULL, 'best_practice', 0.95, 'massive_boost_35', 'system'),
('KEIROAI_BEST_PRACTICES: Le CEO agent doit envoyer un brief concis (5-7 lignes) avec des actions concretes, pas des analyses longues.', 'CEO: brief 5-7 lignes + actions concretes', 'ceo', 'best_practice', 0.92, 'massive_boost_35', 'system'),
('KEIROAI_BEST_PRACTICES: Les agents ne doivent jamais mentionner KeiroAI dans le contenu genere pour le client.', 'Agents: jamais mentionner KeiroAI dans contenu client', NULL, 'best_practice', 0.95, 'massive_boost_35', 'system'),
('KEIROAI_BEST_PRACTICES: Le quota Brevo (300/jour) doit etre respecte. Prioriser les emails haute valeur.', 'Quota Brevo 300/jour: prioriser haute valeur', 'email', 'best_practice', 0.92, 'massive_boost_35', 'system'),
('KEIROAI_BEST_PRACTICES: Les agents doivent s adapter au fuseau horaire du client pour publier et envoyer aux heures optimales.', 'Agents: fuseau horaire client pour horaires optimaux', NULL, 'best_practice', 0.92, 'massive_boost_35', 'system')
INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('ADVANCED_FUNNEL: Le tripwire offer (offre a tres bas prix: 1-7€) convertit les leads en acheteurs. Ensuite upsell vers l offre principale.', 'Tripwire 1-7€ = convertir leads en acheteurs. Puis upsell', 'commercial', 'best_practice', 0.82, 'massive_boost_36', 'system'),
